    "# ============================================================\n",
    "# 3. Run baseline simulations\n",
    "# ============================================================\n",
    "\n",
    "if __name__ == \"__main__\":\n",
    "    gaussian_losses = simulate_vasicek_gaussian()\n",
    "    student_t_losses = simulate_student_t_factor()\n",
    "\n",
    "    gaussian_metrics = calculate_risk_metrics(gaussian_losses)\n",
    "    student_t_metrics = calculate_risk_metrics(student_t_losses)\n",
    "\n",
    "    results = pd.DataFrame(\n",
    "        [gaussian_metrics, student_t_metrics],\n",
    "        index=[\"Gaussian Vasicek\", \"Student-t Factor\"]\n",
    "    )\n",
