    "    print(\"\\nRisk Metrics Comparison\")\n",
    "    print(results)\n",
    "\n",
    "    # Extra: show default-count intuition\n",
    "    gaussian_default_counts = gaussian_losses / (LGD * EAD)\n",
    "    student_t_default_counts = student_t_losses / (LGD * EAD)\n",
    "\n",
